mapper.select:
SELECT

FROM coupon_usage


        AND order_id = #{orderId}


        AND coupon_id = #{couponId}


        AND partner_id = #{partnerId}


        AND place_id = #{placeId}


        AND status = #{status}


        AND created_at >= TO_DATE(#{fromDate}, 'YYYY-MM-DD')


        AND created_at < TO_DATE(#{toDate}, 'YYYY-MM-DD') + 1


ORDER BY usage_id DESC

SELECT
    COUNT(*) AS usageCount,
    NVL(SUM(discount_amount), 0) AS totalDiscountAmount,
    NVL(SUM(platform_discount_amount), 0) AS totalPlatformDiscountAmount,
    NVL(SUM(partner_discount_amount), 0) AS totalPartnerDiscountAmount
FROM coupon_usage


        AND order_id = #{orderId}


        AND coupon_id = #{couponId}


        AND partner_id = #{partnerId}


        AND place_id = #{placeId}


        AND status = #{status}


        AND created_at >= TO_DATE(#{fromDate}, 'YYYY-MM-DD')


        AND created_at < TO_DATE(#{toDate}, 'YYYY-MM-DD') + 1
